const IMGS = {
  dr_rajkumari: "data:image/jpeg;base64,",
  logo: "data:image/png;base64,",
  super_inductive: "data:image/jpeg;base64,",
  robotic: "data:image/jpeg;base64,",
  combo: "data:image/jpeg;base64,",
  icombo: "data:image/jpeg;base64,",
  tecar: "data:image/jpeg;base64,",
  laser: "data:image/jpeg;base64,",
  hospital: "data:image/jpeg;base64,",
  shockwave: "data:image/jpeg;base64,",
  dr_rahul: "data:image/jpeg;base64,",
};

document.addEventListener('DOMContentLoaded', () => {
  // Inject all images
  document.querySelectorAll('img[data-img]').forEach(img => {
    const key = img.getAttribute('data-img');
    if (IMGS[key]) {
      img.src = IMGS[key];
      img.removeAttribute('data-img');
    }
  });

  // Inject video poster
  document.querySelectorAll('[data-poster]').forEach(el => {
    const key = el.getAttribute('data-poster');
    if (IMGS[key]) {
      el.poster = IMGS[key];
      el.removeAttribute('data-poster');
    }
  });

  // Hero fallback background = hospital image
  const heroFallback = document.querySelector('.hero-fallback');
  if (heroFallback && IMGS.hospital) {
    heroFallback.style.backgroundImage = 'url(' + IMGS.hospital + ')';
    heroFallback.style.backgroundSize = 'cover';
    heroFallback.style.backgroundPosition = 'center';
  }

  // Video error fallback
  const video = document.querySelector('.hero-video');
  if (video) {
    video.addEventListener('error', () => { video.style.display = 'none'; });
  }
});
